  ('social-worker-moex-00481', 'social-worker', 'social-worker-moex-113-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '關於社會安全體系的敘述，下列何者錯誤？', '["社會安全可以泛指為一種促成人民以社會團結的形式，來因應所得不足、減少或喪失等風險的 一種集體制度", "社會安全體系可分為：繳保費的給付、資產調查的給付、普及的非繳保費與非資產調查的事故 或分類給付", "社會安全制度都是使用現金給付的方式", "我國社會福利政策綱領宣示，政府應建構以社會保險為主的社會安全體系"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "fc7a23e6eeb3", "answer_pdf_sha1": "9716d6b3463b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00482', 'social-worker', 'social-worker-moex-113-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '關於社會津貼的敘述，下列何者錯誤？', '["社會津貼為一種非繳保費、非資產調查的一種制度", "社會津貼的給付資格通常根據人口屬性或補償原則", "社會津貼的行政通常由政府主導", "社會津貼的財源通常來自社會保險基金"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "fc7a23e6eeb3", "answer_pdf_sha1": "9716d6b3463b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
