  ('social-worker-moex-00486', 'social-worker', 'social-worker-moex-113-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據老人福利法規定，下列有關老人受監護或輔助宣告的敘述，何者正確？', '["老人有受監護或輔助宣告之必要時，直轄市、縣市主管機關得協助其向法院聲請。受監護或輔 助宣告原因消滅時，直轄市、縣市主管機關得協助進行撤銷宣告之聲請", "老人有受監護或輔助宣告之必要時，僅家屬才可向法院提出聲請。受監護或輔助宣告原因消滅 時，必須由聲請者進行撤銷宣告", "老人有受監護或輔助宣告之必要時，僅同戶籍者可向法院提出聲請。受監護或輔助宣告原因消 滅時，由同戶籍者進行撤銷宣告之聲請", "老人有受監護或輔助宣告之必要時，僅老人直系血親可向法院提出聲請。受監護或輔助宣告原 因消滅時，亦須由老人直系血親進行撤銷宣告之聲請"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "fc7a23e6eeb3", "answer_pdf_sha1": "9716d6b3463b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
